import { useState, useEffect } from 'react';

export const useConversation = () => {
  const [messages, setMessages] = useState([]);
  const [isTyping, setIsTyping] = useState(false);
  const [userData, setUserData] = useState({});
  const [currentStep, setCurrentStep] = useState({ type: 'text' }); // LLM will define this

  // Initial greeting
  useEffect(() => {
    const startConversation = async () => {
      setIsTyping(true);
      const initialPrompt = "You are a clinical assistant. Start the NIMHANS case history collection by greeting the patient and asking for their name.";
      const firstQuestion = await callOllama(initialPrompt);
      setMessages([{ sender: 'bot', text: firstQuestion }]);
      setIsTyping(false);
    };
    startConversation();
  }, []);

  const callOllama = async (prompt) => {
    try {
      const response = await fetch("http://localhost:11434/api/generate", {
        method: "POST",
        body: JSON.stringify({
          model: "mistral", // Ensure this matches your 'ollama run' model
          prompt: prompt,
          stream: false,
// Replace the 'system' property inside your callOllama function:
system: `You are a NIMHANS Clinical Interviewer. 
Rule 1: Speak ONLY the next question. Do not explain your reasoning.
Rule 2: Do not jump to suicide risk immediately unless the user mentions self-harm. 
Rule 3: Follow the sequence: Name -> Age/Gender -> Chief Complaints -> History.
Rule 4: Be empathetic and brief.`        }),
      });
      const data = await response.json();
      return data.response;
    } catch (error) {
      console.error("Ollama Error:", error);
      return "I'm having trouble connecting to my local brain. Is Ollama running?";
    }
  };

  const handleUserAnswer = async (answer) => {
    // 1. Add user answer to UI
    setMessages(prev => [...prev, { sender: 'user', text: answer }]);
    setIsTyping(true);

    // 2. Build the context for the LLM
    const context = `
      Current Data Collected: ${JSON.stringify(userData)}
      Patient's last answer: "${answer}"
      Based on the NIMHANS protocol, what is the next logical question to ask?
    `;

    // 3. Get the next question from Ollama
    const nextQuestion = await callOllama(context);
    
    setMessages(prev => [...prev, { sender: 'bot', text: nextQuestion }]);
    setIsTyping(false);
  };

  return { messages, isTyping, currentStep, handleUserAnswer, userData };
};
